import React, { useState } from 'react';
import './styles/claude-theme.css';

import FileUpload from './components/FileUpload';


const mockAnswers = [
    { question: 'What is the document type?', answer: 'PDF' },
    { question: 'Who is the author?', answer: 'Jane Doe' },
    { question: 'Submission date?', answer: '2026-03-30' },
    { question: 'Summary?', answer: 'This is a sample summary of the uploaded document.' },
];

const App: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    // In a real app, answers would be set after processing the file
    const [answers, setAnswers] = useState(mockAnswers);

    const handleFileSelected = (file: File) => {
        setSelectedFile(file);
        // setAnswers([]); // Reset or trigger processing here
    };

    return (
        <div className="landing-page">
            <header className="hero">
                <div className="hero-content">
                    <img src="/logo192.png" alt="EPIFs Assistant Logo" className="hero-logo" />
                    <h1 className="hero-title">EPIFs Assistant</h1>
                    <p className="hero-subtitle">Upload your document and get instant answers to your questionnaire.</p>
                </div>
            </header>
            <main className="main-content">
                <section className="upload-section polished-upload">
                    <FileUpload onFileSelected={handleFileSelected} />
                    {selectedFile && (
                        <div className="file-info polished-file-info">
                            <span className="file-icon">📄</span>
                            <span className="file-name">{selectedFile.name}</span>
                            <span className="file-size">({(selectedFile.size / 1024).toFixed(1)} KB)</span>
                        </div>
                    )}
                </section>
                <section className="results-section">
                    {selectedFile ? (
                        <div className="results-card">
                            <h2 className="results-title">Extracted Answers</h2>
                            <div className="answers-list">
                                {answers.map((item, idx) => (
                                    <div className="answer-row" key={idx}>
                                        <span className="question">{item.question}</span>
                                        <span className="answer">{item.answer}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="results-placeholder">
                            <p className="placeholder-text">Upload a document to see answers here.</p>
                        </div>
                    )}
                </section>
            </main>
            <footer className="footer">
                <span>© {new Date().getFullYear()} EPIFs Assistant. All rights reserved.</span>
            </footer>
        </div>
    );
};

export default App;
